INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Built-in Calling$q$, $q$Make and receive calls directly inside the CRM, with call recording and automatic activity logging against each contact.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Power & Predictive Dialer$q$, $q$Work through call lists faster with dialers that automatically queue up the next call, reducing manual dialing time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Native SMS$q$, $q$Send and receive text messages from within Close, logged alongside calls and emails on the contact timeline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Two-Way Email Sync & Sequences$q$, $q$Sync existing email inboxes and set up automated, multi-step email sequences for outreach and follow-up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Visual Pipeline Management$q$, $q$Track deals through customizable pipeline stages with a drag-and-drop view for reps and managers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Workflow Automation$q$, $q$Automate follow-up tasks, reminders, and multi-channel outreach sequences triggered by lead or deal activity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Reporting & Analytics$q$, $q$Dashboards and reports covering call activity, email performance, and sales pipeline metrics for coaching and forecasting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Custom Fields & Activities$q$, $q$Adapt the data model with custom fields and activity types to match a team's specific sales process.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Open API$q$, $q$A documented API for building custom integrations or syncing data with other business systems.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Third-Party Integrations$q$, $q$Connects with tools like Zapier, Google Workspace, Zoom, and Calendly to extend the core CRM.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Calling, SMS, and email are all built in, reducing the need for separate outreach tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Fast setup and a relatively short learning curve compared to enterprise CRMs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Power and Predictive dialers help high-volume outbound teams work through leads efficiently$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Straightforward pipeline view keeps deal tracking and communication in one screen$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Workflow automation reduces manual follow-up work for reps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Less configurable than large enterprise CRMs for complex organizational structures$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$No built-in marketing automation or customer support ticketing functionality$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Smaller third-party app marketplace compared to major CRM platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Calling minutes and add-ons can increase costs depending on usage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$May feel limited for teams that need deep customization of objects and permissions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$What is Close used for?$q$, $q$Close is a sales CRM used by inside sales teams to manage leads and deals while calling, texting, and emailing prospects from within a single platform.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Does Close have a free trial?$q$, $q$Yes, Close offers a free trial period so teams can test the CRM, calling, and email features before subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Is there a free plan for Close?$q$, $q$Close does not offer a permanent free plan; it is a paid subscription product with tiered pricing based on features and usage.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Does Close have mobile apps?$q$, $q$Close offers mobile apps for iOS and Android so reps can call, text, and manage deals from a phone or tablet.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Can Close integrate with other tools?$q$, $q$Yes, Close supports integrations such as Zapier, Google Workspace, Zoom, and Calendly, along with an open API for custom connections.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Outbound Sales Prospecting$q$, $q$SDRs use Close's Power and Predictive dialers to work through call lists and log every touchpoint automatically.$q$, $q$SDR and BDR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Founder-Led Sales$q$, $q$Early-stage founders manage their own pipeline and outreach without needing a dedicated sales operations setup.$q$, $q$Startup founders and small sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Remote Sales Team Management$q$, $q$Sales managers track call and email activity across a distributed team using built-in reporting dashboards.$q$, $q$Remote sales managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Deal Pipeline Tracking$q$, $q$Sales teams move opportunities through customizable pipeline stages while keeping communication history attached to each deal.$q$, $q$B2B sales teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Startup$q$, $q$From approximately $19/user/month$q$, $q$annual$q$, $q$["Core CRM and pipeline management","Built-in calling and SMS","Email sync and templates","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Professional$q$, $q$From approximately $59/user/month$q$, $q$annual$q$, $q$["Everything in Startup","Power Dialer","Email sequences","Workflow automation","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$Enterprise$q$, $q$From approximately $139/user/month$q$, $q$annual$q$, $q$["Everything in Professional","Predictive Dialer","Custom activities and fields","Advanced permissions and controls","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Close, originally launched as Close.io in 2013, is a sales CRM built around the idea that reps shouldn't need a stack of separate tools to prospect, call, email, and close deals. Instead of bolting a dialer or email tool onto a traditional CRM, Close bakes calling, SMS, and email directly into the pipeline, so outreach and deal tracking happen in one place.$q$, $q$The company has operated as a fully remote, distributed team since its early days, which shaped a product philosophy centered on speed, simplicity, and getting sales reps productive with minimal setup. Close markets itself less as a system of record for enterprise operations and more as a working tool that inside sales teams use dozens of times a day.$q$, $q$Over the years Close has added workflow automation, predictive and power dialers, email sequences, and reporting, but it has generally resisted becoming a sprawling platform. The result is a CRM that is opinionated about supporting high-velocity, call-and-email-heavy sales motions rather than trying to be everything to every type of go-to-market team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$who-its-for$q$, $q$Who Close Is For$q$, 2, ARRAY[$q$Close is best suited to small and mid-sized B2B companies, especially startups and scale-ups, where a lean sales team is doing a high volume of outbound calling and emailing. Inside sales reps, SDRs, and BDRs who spend most of their day on the phone benefit directly from built-in calling features that eliminate the need for a separate dialer subscription.$q$, $q$It also fits sales leaders who want a CRM that can be configured and adopted quickly without a lengthy implementation project or a dedicated CRM administrator. Because Close is cloud-based and doesn't require heavy IT involvement, remote and distributed sales teams often find it straightforward to roll out.$q$, $q$Founders and small sales teams moving off spreadsheets, or teams that previously duct-taped together a CRM plus a separate calling app, are a common fit, since Close consolidates those workflows into a single subscription and interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex org structures, multi-department approval workflows, or deep custom object requirements will likely find Close's data model and configurability more limited than platforms like Salesforce. Teams that need extensive role-based permission hierarchies or industry-specific compliance customization may hit ceilings.$q$, $q$Companies that need robust marketing automation, customer support ticketing, or a broad third-party app marketplace as part of the same platform should look elsewhere, since Close is focused specifically on the sales pipeline rather than being a full revenue-operations suite.$q$, $q$Organizations already standardized on a larger CRM ecosystem, or those that rely heavily on a vast library of pre-built integrations and partner apps, may find Close's integration catalog narrower by comparison, even though it does connect with common tools like Zapier and Google Workspace.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Close's signature feature is its built-in calling, including a Power Dialer and Predictive Dialer for working through call lists quickly, plus native SMS messaging, all logged automatically against the relevant contact and deal. Email is similarly built in, supporting two-way sync with existing inboxes and automated, multi-step email sequences for outreach and follow-up.$q$, $q$Pipeline management gives reps and managers a visual view of deals by stage, and Workflows lets teams automate repetitive follow-up tasks and reminders. Reporting dashboards surface call activity, email performance, and pipeline metrics so managers can track rep productivity without exporting data elsewhere.$q$, $q$Custom fields and custom activities allow teams to adapt the CRM to their own sales process, and an open API plus integrations (such as Zapier, Zoom, and Calendly) let Close connect into a broader tech stack when needed.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63a64c42-cc4a-45fb-b461-783e43ab44aa', $q$close-experience$q$, $q$The Close Experience$q$, 2, ARRAY[$q$Day to day, using Close feels closer to using a communications tool than a traditional database-style CRM. The interface is built around the list of leads or deals a rep is working through right now, with calling, texting, and emailing available directly from that view rather than in a separate app.$q$, $q$New users generally report a shorter ramp-up time than with heavier enterprise CRMs, since there are fewer configuration screens and less need for an administrator to model the system before reps can start using it. That simplicity is part of the trade-off: teams wanting extensive customization or a large ecosystem of add-ons will find Close comparatively streamlined.$q$, $q$Overall, the experience rewards teams whose sales process centers on high-frequency phone and email touches, giving reps a single screen to move quickly from one conversation to the next while keeping activity history automatically attached to each contact and deal.$q$]::text[], 4);
