INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Client Communication Portal$q$, $q$A shared online workspace where homeowners can view project updates, message the builder, and stay in the loop without relying on email or phone calls.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Specs & Selections$q$, $q$Tracks material and finish selections against allowances, showing the client and builder the real-time budget impact of every choice.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Budgeting & Estimating$q$, $q$Cost catalogs, proposals, and budget-to-actual tracking by cost code, built around the way custom builders and remodelers price jobs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Scheduling$q$, $q$Project schedules with subcontractor-facing views to coordinate trade sequencing and keep everyone aligned on timing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Change Order Management$q$, $q$Digital change orders with e-signatures that automatically flow through to the budget and the client portal.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Documents, Photos & Plan Markup$q$, $q$Centralized storage for plans, permits, and job-site photos, with annotation tools for reviewing drawings with clients or trades.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Time Tracking$q$, $q$Crew and subcontractor time entry tied back to jobs and cost codes for labor cost tracking.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Warranty Management$q$, $q$A dedicated module for logging, assigning, and closing out post-closing warranty and service requests.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Mobile Apps$q$, $q$iOS and Android companion apps that give field staff access to schedules, photos, messages, and task lists on the job site.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Purpose-built for the custom home building and remodeling workflow, including selections, allowances, and client-facing change orders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Strong client communication portal that reduces email and phone back-and-forth with homeowners$q$, 1);
