INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Budgeting tools tailored to construction cost codes rather than generic project accounting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$A defined, supported migration path to Buildertrend for customers who need to transition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$In maintenance mode since the 2021 acquisition, with little to no new feature development$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Not open to meaningful new customer growth; the vendor is actively directing prospects to Buildertrend instead$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Pricing is no longer published on the company's site and requires contacting sales or support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$User reports describe slower support response times compared to CoConstruct's earlier, independent years$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$A defined cutoff for creating new projects means long-term commitment to the platform itself is not realistic$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Is CoConstruct still available to new customers?$q$, $q$CoConstruct is in maintenance mode and is not being actively marketed to new customers. Parent company ECI Software Solutions is directing prospective and existing customers toward Buildertrend, its sister platform, as the long-term product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What happens to my data if I'm an existing CoConstruct customer?$q$, $q$According to CoConstruct's own migration guidance, historical project data is retained and accessible indefinitely, and a dedicated migration team assists existing customers moving their projects into Buildertrend.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What's the difference between CoConstruct and Buildertrend?$q$, $q$Both are residential construction management platforms with overlapping features (budgeting, scheduling, client communication, selections). Buildertrend acquired CoConstruct in 2021, and both now operate under parent company ECI Software Solutions, with Buildertrend positioned as the platform going forward.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$How much does CoConstruct cost?$q$, $q$CoConstruct no longer publishes pricing directly on its website; prospective and existing customers are directed to contact sales or support for current terms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What types of companies typically use CoConstruct?$q$, $q$Custom home builders, remodelers, and specialty residential contractors who manage a smaller number of high-touch, client-facing projects rather than high-volume production building or commercial work.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Managing client selections and allowances$q$, $q$Tracking dozens of finish and material choices per project against allowance budgets, and showing homeowners the cost impact of each decision in real time.$q$, $q$Custom home builders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Coordinating multi-project remodels$q$, $q$Running several concurrent remodeling jobs with different clients, timelines, and finish selections from a single system.$q$, $q$Remodeling companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Managing change orders and budgets together$q$, $q$Keeping change order approvals, e-signatures, and budget adjustments in sync so cost overruns are caught and communicated before closeout.$q$, $q$Design-build firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Transitioning off a sunsetting platform$q$, $q$Using CoConstruct's built-in migration tools and support to move active and historical projects onto Buildertrend ahead of the new-project cutoff.$q$, $q$Existing CoConstruct customers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Core$q$, $q$Historically around $199/month$q$, $q$monthly (2 users, last publicly documented rate)$q$, $q$["Client communication portal","Specs & selections","Basic budgeting and scheduling","Not currently published or sold on coconstruct.com"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Essential$q$, $q$Historically around $399/month$q$, $q$monthly (5 users, last publicly documented rate)$q$, $q$["Everything in Core","Expanded budgeting and change order tools","Proposal and estimating features","Not currently published or sold on coconstruct.com"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Advanced$q$, $q$Historically around $599/month$q$, $q$monthly (unlimited users, last publicly documented rate)$q$, $q$["Everything in Essential","Unlimited users and warranty projects","Dedicated implementation support","Not currently published or sold on coconstruct.com"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Current status (2026)$q$, $q$Contact sales$q$, NULL, $q$["CoConstruct is in maintenance mode under parent company ECI Software Solutions","New sign-ups are being redirected to Buildertrend","Existing customers continue on legacy plans while a formal migration path is offered"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CoConstruct is construction management software built specifically for custom home builders, remodelers, and specialty residential contractors. Founded by Donny Wyatt after a frustrating experience building his own home, the platform grew over roughly two decades into one of the more established names in residential construction software, centering its workflow around client-facing selections, specs, budgets, schedules, and project communication rather than the broader commercial job-costing tools built for general contractors.$q$, $q$The product's whole premise was to replace the scattered emails, phone calls, and spreadsheets that typically accompany a custom build with one shared system that both the builder and the homeowner log into. That client-in-the-loop design, rather than a purely internal project-management tool, is what differentiated CoConstruct from generic construction software for most of its history.$q$, $q$In February 2021, CoConstruct was acquired by Buildertrend, with both companies operating under parent company ECI Software Solutions. Since the merger, CoConstruct has effectively moved into maintenance mode: it continues to serve existing customers, but ECI has been steadily consolidating its residential construction portfolio onto the Buildertrend platform, with a formal migration path and cutoff dates for new projects. Anyone evaluating CoConstruct today is really evaluating a legacy product with a defined transition plan, not an actively growing platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$who-its-for$q$, $q$Who CoConstruct Is For$q$, 2, ARRAY[$q$CoConstruct was built for small-to-midsize custom home builders and remodeling companies that manage a handful of concurrent, high-touch client projects rather than a large volume of low-touch ones. Its selections and specs modules, in particular, were designed around the reality of custom construction, where a homeowner needs to review dozens of finish choices, allowances, and change orders over the life of a build, and the builder needs a single system to keep that dialogue, and the associated cost impact, organized.$q$, $q$Remodelers who juggle several active jobs with different clients, timelines, and finish selections at once are a similarly natural fit, since the platform's budgeting-against-allowances approach was designed for exactly that kind of variability. Design-build firms that sell the client experience as much as the construction itself also tend to value the polished, homeowner-facing portal.$q$, $q$Existing CoConstruct customers who are already comfortable with the interface, have integrated it with their accounting workflow, and don't want to disrupt active projects mid-build are the most natural fit for continuing to use it in the near term. It also suits builders who value a mature, full-featured tool over a newer, leaner one, since CoConstruct's feature set was refined over many years of direct feedback from residential trades before development slowed following the acquisition.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Builders and remodelers who are not already on CoConstruct should generally look elsewhere. The product is in maintenance mode, is not being actively marketed to new customers, and its own migration materials point prospective and existing users toward Buildertrend, with new-project creation inside CoConstruct set to end and a formal migration deadline for remaining accounts. Starting fresh on a platform that's being wound down creates unnecessary switching risk and wasted onboarding effort.$q$, $q$Commercial general contractors and companies whose work is primarily bid-and-build rather than client-facing custom construction are also a poor fit, since CoConstruct's tools are oriented around homeowner communication and selections rather than heavy-duty commercial job costing, prevailing-wage compliance, or large subcontractor networks.$q$, $q$Teams that need active, ongoing product investment, frequent new features, or up-to-date third-party integrations should weigh that against a platform whose vendor has openly been directing engineering resources toward its sister product instead. Builders prioritizing long-term platform stability are generally better served by evaluating Buildertrend directly, or a newer competitor, rather than committing to CoConstruct.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$CoConstruct's core strength is its client-facing communication layer: a shared online portal where homeowners can view schedules, approve selections, sign change orders, and message the builder without relying on email threads or phone calls. Layered on top of that is a specs and selections system that tracks allowances against actual costs, so a builder can show a client the budget impact of upgrading a fixture or finish in real time.$q$, $q$Budgeting and estimating tools let builders build cost catalogs, generate proposals, and track budget-to-actual variance by cost code, while a project schedule module, with subcontractor-facing views, coordinates trade sequencing across the life of a build. Change order management ties directly into the budget and client portal so approvals and cost adjustments stay in sync automatically rather than being re-entered by hand.$q$, $q$Document and photo storage keeps plans, permits, and job-site photos attached to the relevant project, with markup and annotation tools for reviewing drawings with clients or trades. Time tracking, an internal to-do and task system, and a warranty module for handling post-closing service requests round out the back-office side, while companion iOS and Android apps give builders and site supervisors field access to schedules, photos, and messages from the job site.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$the-coconstruct-experience$q$, $q$The CoConstruct Experience$q$, 2, ARRAY[$q$Day to day, using CoConstruct feels like managing a construction project through a single shared workspace with the client rather than through scattered emails, spreadsheets, and phone calls. Builders who adopted it in its more actively developed years generally describe the learning curve as moderate, given how much ground the software tries to cover, but describe the payoff as fewer client miscommunications, cleaner audit trails on selections, and fewer disputes over change-order costs at closeout.$q$, $q$Since the Buildertrend acquisition, the experience has shifted for many long-time customers: independent reviews and user reports commonly note that feature updates have slowed considerably, support responsiveness has declined from its earlier reputation, and the product's own in-app messaging now actively nudges customers toward migrating to Buildertrend rather than introducing new capabilities within CoConstruct itself.$q$, $q$For a directory evaluation today, the honest characterization is a capable, purpose-built tool for its era, one that built genuine loyalty among custom builders for its client communication model, but that current and prospective users should approach with its transition trajectory clearly in mind rather than as a long-term platform bet.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
