INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Conditional logic$q$, $q$Show, hide, or require fields dynamically based on a respondent's previous answers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Excel-style calculations$q$, $q$Build formulas that reference other fields to compute totals, pricing, scores, or eligibility in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Integrated payments$q$, $q$Accept payments directly on a form through Stripe, PayPal, Square, or Authorize.Net without a separate checkout step.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Repeating sections and tables$q$, $q$Let respondents add multiple line items, such as order quantities or additional guests, within a single submission.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Electronic signatures$q$, $q$Collect legally binding e-signatures as part of a form submission for contracts, waivers, or approvals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Workflow and approvals$q$, $q$Route submitted entries through multi-step approval chains for internal processes like purchase requests or onboarding.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Save and resume$q$, $q$Allow respondents to save a partially completed long form and return to finish it later.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Document generation$q$, $q$Automatically merge entry data into PDF or Word document templates for contracts, receipts, or reports.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Templates library$q$, $q$Start from a large collection of prebuilt form templates for common use cases across industries.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$API and integrations$q$, $q$Connect forms to other systems through a native API, Zapier, Microsoft Power Automate, and direct integrations.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Generous free-forever plan with unlimited forms, not just a time-limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Calculation and conditional logic engine is unusually powerful for a form builder$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Native payment collection covers multiple processors without extra add-ons$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Built-in workflow and approval routing suits internal operations use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Large template library shortens setup for common form types$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Entry-based pricing can grow expensive for high-submission-volume organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$User and guest limits on lower tiers require upgrading as teams grow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Advanced formulas and logic have a steeper learning curve than basic form builders$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Visual design and branding options are less flashy than conversational-style competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$HIPAA compliance and single sign-on are restricted to the top-tier Enterprise plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Is Cognito Forms free to use?$q$, $q$Yes, Cognito Forms offers a free Individual plan with unlimited forms, up to 100 entries per month, and access to core features like conditional logic and payments; paid plans raise entry limits, add users, and unlock features like e-signatures and workflows.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Does Cognito Forms support online payments?$q$, $q$Yes, forms can collect payments directly through integrations with Stripe, PayPal, Square, and Authorize.Net, so respondents can pay while submitting a form without a separate checkout.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Is Cognito Forms HIPAA compliant?$q$, $q$Cognito Forms offers HIPAA compliance with a signed Business Associate Agreement on its Team and Enterprise plans, which is relevant for healthcare organizations collecting patient information.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Do I need coding skills to use Cognito Forms?$q$, $q$No, Cognito Forms is a no-code platform built around a visual drag-and-drop editor, though building advanced calculations and conditional logic does involve a learning curve similar to spreadsheet formulas.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$What does Cognito Forms integrate with?$q$, $q$Cognito Forms connects to other tools through a native API, Zapier, and Microsoft Power Automate, along with direct integrations such as Salesforce and Mailchimp.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Nonprofit donation and event forms$q$, $q$Collect donations with integrated payment processing and manage event registrations with capacity limits and automated confirmations.$q$, $q$Nonprofits and membership associations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Small business order and quote forms$q$, $q$Build forms that calculate pricing, taxes, and shipping automatically based on customer selections.$q$, $q$Small businesses and solopreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Internal approval workflows$q$, $q$Route purchase requests, expense reports, or onboarding paperwork through multi-step approval chains with e-signatures.$q$, $q$Operations, HR, and finance teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Registration and application forms$q$, $q$Manage volunteer sign-ups, membership applications, or program registrations with conditional logic and save-and-resume.$q$, $q$Schools, community organizations, and associations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Individual$q$, $q$Free$q$, NULL, $q$["Unlimited forms","100 entries per month","1 user","100 MB storage","Payment collection included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Pro$q$, $q$$19/month billed annually$q$, $q$monthly or annual$q$, $q$["2,000 entries per month","2 users","1 GB storage","Electronic signatures","Save and resume","Remove Cognito Forms branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Team$q$, $q$$39/month billed annually$q$, $q$monthly or annual$q$, $q$["10,000 entries per month","5 users plus 5 guests","10 GB storage","Client portal","Workflow and approvals","Data lookups"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Enterprise$q$, $q$$129/month billed annually$q$, $q$monthly or annual$q$, $q$["Unlimited entries","20 users plus 20 guests","100 GB storage","HIPAA compliance","Folder permissions","Single sign-on"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cognito Forms is an online form builder created by Cognito, LLC, a Columbia, South Carolina company founded in 2013 by Jamie Thomas and Jennifer Dellacroce. It was built to bridge the gap between simple survey tools and full custom applications, letting non-developers create forms that handle real business logic rather than just collecting text answers.$q$, $q$The platform's signature strength is its formula engine: users can build spreadsheet-style calculations, conditional show/hide logic, repeating sections and tables, and dynamic pricing directly into a form without writing code. On top of that, it layers native payment processing (Stripe, PayPal, Square, Authorize.Net), electronic signatures, save-and-resume, and multi-step approval workflows.$q$, $q$Cognito Forms operates on a freemium model, with a genuinely usable free tier and paid plans that unlock higher entry volumes, more users, and enterprise features like HIPAA compliance and single sign-on. The company was acquired by private equity firm Inverness Graham in 2025 but continues to operate under the Cognito Forms brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$who-its-for$q$, $q$Who Cognito Forms Is For$q$, 2, ARRAY[$q$Small businesses and solopreneurs are a natural fit, especially those that need quote calculators, order forms, or booking forms that do math on the fly (shipping costs, quantity discounts, tax) without hiring a developer or juggling spreadsheets after the fact.$q$, $q$Nonprofits and membership associations rely heavily on Cognito Forms for donation forms with integrated payment processing, event registration with capacity limits, volunteer sign-ups, and membership applications — use cases the product markets itself around directly.$q$, $q$Internal operations, HR, and finance teams also get real value from it: purchase requests, expense reimbursement, employee onboarding, and other processes that need e-signatures, file uploads, and routed multi-step approvals rather than a static PDF passed around by email.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that prioritize a highly polished, conversational-style front end — the one-question-at-a-time, animation-heavy feel popularized by tools like Typeform — will likely find Cognito Forms more utilitarian in appearance. It's built for logic and function first, visual flair second.$q$, $q$Organizations with very high monthly submission volumes may find the entry-based pricing tiers add up faster than platforms with flat unlimited-response pricing, so it's worth mapping expected volume against the plan limits before committing.$q$, $q$Companies whose workflow already lives deeply inside a CRM like Salesforce or HubSpot may prefer that platform's native form tools for tighter data sync, rather than layering a separate standalone form builder on top, even one as capable as Cognito Forms.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core is conditional logic and calculations: fields can appear, hide, or auto-populate based on other answers, and formulas can reference multiple fields the way spreadsheet formulas reference cells, enabling live pricing, scoring, or eligibility checks inside the form itself.$q$, $q$Data-collection features go beyond single submissions, with repeating sections and tables for line items, file uploads, electronic signatures, save-and-resume for long forms, and a client portal where respondents can view or edit their own past entries.$q$, $q$Operationally, forms can trigger multi-step approval workflows, generate merged PDF or Word documents from submitted data, and connect outward through a native API, Zapier, and Microsoft Power Automate, alongside direct integrations with tools like Salesforce and Mailchimp.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$the-cognito-forms-experience$q$, $q$The Cognito Forms Experience$q$, 2, ARRAY[$q$Building a form feels part spreadsheet, part form designer: the drag-and-drop editor is straightforward for basic fields, but unlocking the calculation engine and nested logic has a real learning curve, softened somewhat by a library of hundreds of pre-built templates to start from.$q$, $q$Once published, forms embed cleanly into existing websites and render responsively on mobile, while the entries dashboard provides views, filtering, and reporting on submitted data without needing to export to a separate tool for basic analysis.$q$, $q$Support is delivered through documentation, a community forum, and email or chat support on paid plans, and the overall experience positions Cognito Forms squarely between bare-bones tools like Google Forms and heavier database-application platforms — more powerful than the former, simpler to pick up than the latter.$q$]::text[], 4);
